import { useState, useEffect } from "react";
import { MdArrowBack } from "react-icons/md";
import { FaLock } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import "./forgotpassword.css";

const ResetPassword = () => {
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  
  const navigate = useNavigate();
  const email = localStorage.getItem("resetEmail");

  useEffect(() => {
    if (!localStorage.getItem("otpVerified")) {
      navigate("/forgot-password");
    }
  }, [navigate]);

  const validatePassword = (password) => {
    return /^(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/.test(password);
  };

  const handlePasswordReset = async (e) => {
    e.preventDefault();

    if (!newPassword || !confirmPassword) {
      setError("All fields are required!");
      return;
    }

    if (newPassword !== confirmPassword) {
      setError("Passwords do not match!");
      return;
    }

    if (!validatePassword(newPassword)) {
      setError("Password must have at least 8 characters, an uppercase letter, a number, and a symbol.");
      return;
    }

    setLoading(true);
    try {
      const response = await axios.post("http://localhost:5000/api/auth/reset-password", {
        email,
        newPassword,
      });

      setSuccess(response.data.message);
      localStorage.removeItem("otpVerified");
      localStorage.removeItem("resetEmail");
      setTimeout(() => navigate("/"), 2000);
    } catch (error) {
      setError(error.response?.data?.message || "Password reset failed!");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="reset-password-container">
      <div className="back-to-login" onClick={() => navigate("/")}> <MdArrowBack /> </div>
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <h2 className="reset-password-title">Reset Password</h2>
      <p className="instruction-text">Enter a strong new password.</p>

      <form onSubmit={handlePasswordReset} className="reset-password-form">
        <div className="input-group">
          <FaLock className="icon" />
          <input
            type="password"
            placeholder="New Password"
            value={newPassword}
            onChange={(e) => setNewPassword(e.target.value)}
          />
        </div>

        <div className="input-group">
          <FaLock className="icon" />
          <input
            type="password"
            placeholder="Confirm Password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
          />
        </div>

        <button type="submit" className="reset-button" disabled={loading}>
          {loading ? "Updating..." : "Reset Password"}
        </button>

        <div className="message-container">
          {error && <p className="error-message">{error}</p>}
          {success && <p className="success-message">{success}</p>}
        </div>
      </form>
    </div>
  );
};

export default ResetPassword;
